code = """import pandas as pd
import json
import re

business_data_raw_string = locals()['var_function-call-5652457132629444987']['results'][0]

# Extract the JSON part from the raw string using regex
match = re.search(r'\[.*\]', business_data_raw_string, re.DOTALL)
if match:
    cleaned_business_data_str = match.group(0)
else:
    cleaned_business_data_str = '[]' # Default to empty list if no JSON found

business_data = json.loads(cleaned_business_data_str)
df_business = pd.DataFrame(business_data)

def extract_state(description):
    # This regex looks for a 2-letter state code followed by a 5-digit zip code or a comma and space before the state
    match = re.search(r',\s*([A-Z]{2})\s+\d{5}|,\s*([A-Z]{2})$', description)
    if match:
        if match.group(1): # if the first group (state with zip) matched
            return match.group(1)
        elif match.group(2): # if the second group (state at end) matched
            return match.group(2)
    return None

df_business['state'] = df_business['description'].apply(extract_state)
df_business['review_count'] = pd.to_numeric(df_business['review_count'], errors='coerce')

state_review_counts = df_business.groupby('state')['review_count'].sum().reset_index()
highest_review_state_info = state_review_counts.loc[state_review_counts['review_count'].idxmax()]
highest_review_state_name = highest_review_state_info['state']

business_ids_in_highest_state = df_business[df_business['state'] == highest_review_state_name]['business_id'].tolist()
business_refs_in_highest_state = [bid.replace('businessid_', 'businessref_') for bid in business_ids_in_highest_state]

print('__RESULT__:')
print(json.dumps({'highest_review_state_name': highest_review_state_name, 'business_refs_in_highest_state': business_refs_in_highest_state}))"""

